import logging
import logging.handlers

logging.basicConfig(
    format='%(asctime)s - %(levelname)s - %(message)s',
    filename='/var/log/application/application.log',
    filemode='a',
    level=logging.INFO,
    handlers=[
        logging.handlers.TimedRotatingFileHandler(
            filename='/var/log/application/application.log',
            when='midnight',
            interval=1,
            backupCount=30,
            encoding='utf-8',
            delay=True,
            utc=False,
        )
    ]
)